using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: inline DataRow for simple primitive combos ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for invalid-input cases ---

    [TestMethod]
    [DynamicData(nameof(InvalidCalculateTotalInputs))]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRange(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, string expectedParam)>
        InvalidCalculateTotalInputs =>
    [
        (-1m, 1, 0.1m, "unitPrice"),
        (10m, -1, 0.1m, "quantity"),
        (10m, 1, -0.01m, "taxRate"),
        (10m, 1, 1.01m, "taxRate"),
    ];

    // --- ApplyDiscount: DataRow for common discount scenarios ---

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% off")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(49.99, 25.0, 37.4925, DisplayName = "Fractional result")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price, any discount")]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: boundary violations ---

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Discount below 0")]
    [DataRow(100.01, DisplayName = "Discount above 100")]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRange(double discount)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discount));
    }

    // --- FormatPrice: DynamicData with ValueTuples for string results ---

    [TestMethod]
    [DynamicData(nameof(FormatPriceTestData))]
    public void FormatPrice_VariousInputs_ReturnsFormattedString(
        decimal price, string? symbol, string expected)
    {
        var result = symbol is null
            ? _calculator.FormatPrice(price)
            : _calculator.FormatPrice(price, symbol);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, string? symbol, string expected)> FormatPriceTestData =>
    [
        (9.99m, null, "$9.99"),
        (9.99m, "€", "€9.99"),
        (1000m, "$", "$1000.00"),
        (0m, "£", "£0.00"),
        (3.1m, "$", "$3.10"),
    ];
}

